PREFIX wd: <http://www.wikidata.org/entity/>
PREFIX wdt: <http://www.wikidata.org/prop/direct/>
SELECT(MIN(?games) AS ?minGames) WHERE {
  VALUES ?year_str {
    "1975" "1986" "2004" "2007" "2013" "2018"
  }
  ?series wdt:P31 wd:Q1529013 ; wdt:P1346 wd:Q213959 ; wdt:P585 ?date ; wdt:P1350 ?games .
  FILTER(SUBSTR(STR(?date) , 1 , 4) = ?year_str)
}
